def upgrade() -> None:
    bind = op.get_bind()
    if bind.dialect.name != "postgresql":
        # Katalog-Paritaet ist PostgreSQL-only (SQLite-Test-Runs skippen).
        return
    for _section, _stmts in _SECTIONS:
        for _stmt in _stmts:
            op.execute(_stmt)


def downgrade() -> None:
    # Bewusst No-op: siehe Docstring.
    bind = op.get_bind()
    if bind.dialect.name != "postgresql":
        return
